import Foundation

enum RaycastScriptCommandIcon {
	static let light: Data = Self.decode(
		""
	)

	static let dark: Data = Self.decode(
		""
	)
}

extension RaycastScriptCommandIcon {
	private static func decode(_ value: String) -> Data {
		guard let data = Data(base64Encoded: value)
		else { preconditionFailure("Invalid embedded Raycast Script Command icon.") }
		return data
	}
}
